const tavernRoles = ['Barkeep','Barmaid','Regular','Suspicious Stranger','Off-duty Guard','Traveling Merchant','Local Gossip','Drunk Noble','Shady Courier','Wandering Bard','Hedge Wizard','Retired Soldier','Fugitive in Disguise','Foreign Spy','Grieving Widow','Young Pickpocket','Bounty Hunter (off-duty)','Disgraced Priest','Lost Adventurer','Fence']

export function generateTavern() {
  const pick = a => a[Math.floor(Math.random() * a.length)]
  const name = `The ${pick(tavernAdj)} ${pick(tavernNoun)}`
  const vibe = pick(tavernVibes)
  const npcs = Array.from({ length: 3 }, () => ({
    role: pick(tavernRoles),
    adj: pick(npcAdjectives),
    quirk: pick(npcQuirks),
  }))
  return { name, vibe, npcs }
}

