const factionAdj = ['Shadow','Iron','Silver','Golden','Crimson','Jade','Obsidian','Amber','Ivory','Copper','Blood','Storm','Frost','Emerald','Bone','Gilded','Hollow','Ancient','Fractured','Burning','Pale','Silent','Scarlet','Veiled','Ashen']
const factionNoun = ['Hand','Fang','Chain','Crown','Eye','Blade','Coin','Shield','Feather','Hammer','Serpent','Wing','Claw','Ring','Star','Quill','Mask','Circle','Oath','Throne','Web','Veil','Brand','Compass','Lantern']
export const factionPurposes = ['A thieves\' guild that maintains order by controlling all crime — officially, they don\'t exist.','A merchant consortium whose trade interests have grown into political control.','A secret society dedicated to preserving forbidden knowledge from the wrong hands.','An assassins\' brotherhood operating on a strict moral code that most find paradoxical.','A cult working toward a prophecy they believe is inevitable — and beneficial to some.','A network of spies serving no government, only the balance of power itself.','A revolutionary movement that started as a labor union and became something more dangerous.','A religious order that has drifted significantly from the institution that created it.','A coalition of dispossessed nobles quietly working to reclaim what was taken from them.','An ancient order of monster hunters who know things the public is not allowed to know.','A criminal empire operating entirely through legitimate businesses, invisible in plain sight.','A collective of arcane researchers studying things no responsible institution would sanction.','A military brotherhood that exists outside any nation\'s command structure.','A network of refugees from a destroyed civilization, working to restore what was lost.','A neutral arbitration guild ensuring all parties honor agreements — by any means necessary.','A guild of information brokers with no allegiance except to the value of information.','A charity organization that is genuinely charitable — and uses that access for other purposes.','An explorers\' society that funds expeditions and keeps the most important discoveries secret.',]
export const factionTraits = ['Publicly visible but widely misunderstood in their true purpose','Known only to members — outsiders don\'t know they exist','Feared by the powerful, trusted by common folk','Operates openly under a completely different name','No one knows who leads them — including most members','The leader is well-known; the organisation they run is the secret','Has infiltrated every major institution in the city','Currently fracturing over a fundamental internal disagreement','Will work with absolutely anyone for the right price','Has one absolute unbreakable rule — everyone knows what it is','Membership is inherited; you are born in or not at all','Has a rival faction almost identical in structure and purpose','Membership is public — their actual capabilities are the secret','Recently lost their leader and the succession is unsettled','Has a public-facing charitable arm that is completely genuine',]
export function generateFaction() {
  const p = a => a[Math.floor(Math.random() * a.length)]
  return { name: `The ${p(factionAdj)} ${p(factionNoun)}`, purpose: p(factionPurposes), trait: p(factionTraits) }
}

