export const npcHeights = ['Very short (under 5\')','Short (5\'–5\'5")','Average (5\'6"–5\'10")','Tall (5\'11"–6\'3")','Very tall (over 6\'3")']
export const npcBuilds = ['Gaunt and hollow-cheeked','Lean and wiry','Average build','Stocky and solid','Heavyset','Broad and muscular','Hunched, as if carrying weight']
export const npcHairStyles = ['Shaved','Cropped close','Military-short','Medium length, neat','Long and straight','Long and curly','Wild and unkempt','Tightly braided','Pulled back severely','Bald (by nature or choice)']
export const npcHairColors = ['Black','Dark brown','Chestnut brown','Dirty blonde','Golden blonde','Auburn','Bright red','Silver-streaked brown','Grey','White','Dyed — an unusual deliberate shade']
export const npcEyeColors = ['Deep brown','Light brown','Blue','Grey','Green','Hazel','Nearly black','Amber gold','Mismatched — one light, one dark','One milky-white, blind']
export const npcFeatures = ['A deep scar running across one cheek','A scar bisecting one eyebrow and continuing to the jaw','A long puckered scar along the neck','Missing two fingers on the left hand','A prosthetic hand, clearly well-maintained','A prosthetic leg — walks without a limp after years of practice','Burns covering one forearm and hand','Burns on the side of the face — old, well-healed','A tattoo of a serpent curling from wrist to shoulder','A sailor\'s tattoo — anchor, compass rose, and coordinates — fading with age','Ceremonial scarification in geometric patterns across both cheeks','A foreign military brand on the inner wrist','A birthmark on the neck, vaguely map-shaped','A broken nose, poorly set, shifted noticeably to one side','Calloused hands — the specific callouses of someone who has fought for decades','Calloused hands — the specific callouses of a metalworker','Walks with a permanent limp from an old wound','One eye that seems to shift color in different light','Wears a patch over one eye — occasionally switches which eye it covers','Fine silver threads in their hair — clearly magical','No visible distinguishing marks whatsoever — unusually unremarkable',]
export const npcAgeImpressions = ['Looks significantly younger than they are','Looks about their age','Looks older than they are — a hard life written in their face','Completely indeterminate age — anywhere from 30 to 70']
export function generateAppearance() {
  const p = a => a[Math.floor(Math.random() * a.length)]
  const featurePool = [...npcFeatures]
  const numFeatures = Math.random() < 0.4 ? 2 : 1
  const features = []
  for (let i = 0; i < numFeatures; i++) {
    const idx = Math.floor(Math.random() * featurePool.length)
    features.push(featurePool.splice(idx, 1)[0])
  }
  return { height: p(npcHeights), build: p(npcBuilds), hair: `${p(npcHairColors)}, ${p(npcHairStyles).toLowerCase()}`, eyes: p(npcEyeColors), features, age: p(npcAgeImpressions) }
}

